document.addEventListener("alpine:init",()=>{Alpine.data("flavorComposer",()=>({pasoActual:"plantillas",perfilSeleccionado:flavorComposerData.perfilActivo||"personalizado",modulosActivos:flavorComposerData.modulosActivos||[],categoriaFiltrada:"todos",perfiles:flavorComposerData.perfiles||{},categorias:flavorComposerData.categorias||{},modulosRegistrados:flavorComposerData.modulosRegistrados||{},nonces:flavorComposerData.nonces||{},adminPostUrl:flavorComposerData.adminPostUrl||"",cargando:!1,irAPaso(o){this.pasoActual=o},esPerfilActivo(o){return this.perfilSeleccionado===o},cambiarPerfil(o){if(this.cargando)return;if(this.perfilSeleccionado===o)return;if(!confirm(flavorComposerData.i18n.confirmarCambioPerfil||"¿Deseas cambiar de plantilla?"))return;this.cargando=!0;const e=document.createElement("form");e.method="POST",e.action=this.adminPostUrl;const t={action:"flavor_chat_ia_cambiar_perfil",perfil_id:o,_wpnonce:this.nonces.cambiarPerfil};Object.entries(t).forEach(([o,t])=>{const a=document.createElement("input");a.type="hidden",a.name=o,a.value=t,e.appendChild(a)}),document.body.appendChild(e),e.submit()},esModuloActivo(o){return this.modulosActivos.includes(o)},esModuloRequerido(o){const e=this.perfiles[this.perfilSeleccionado];return!!e&&(e.modulos_requeridos||[]).includes(o)},toggleModulo(o){if(this.cargando)return;if(this.esModuloRequerido(o))return;this.cargando=!0;const e=!this.esModuloActivo(o),t=document.createElement("form");t.method="POST",t.action=this.adminPostUrl;const a={action:"flavor_chat_ia_toggle_modulo",modulo_id:o,activar:e?"1":"0",_wpnonce:this.nonces.toggleModulo};Object.entries(a).forEach(([o,e])=>{const a=document.createElement("input");a.type="hidden",a.name=o,a.value=e,t.appendChild(a)}),document.body.appendChild(t),t.submit()},filtrarCategoria(o){this.categoriaFiltrada=o},obtenerModulosFiltrados(){if("todos"===this.categoriaFiltrada)return Object.keys(this.categorias).reduce((o,e)=>o.concat(this.categorias[e].modulos||[]),[]);const o=this.categorias[this.categoriaFiltrada];return o&&o.modulos||[]},obtenerInfoModulo(o){return this.modulosRegistrados[o]||{name:o.charAt(0).toUpperCase()+o.slice(1).replace(/_/g," "),description:""}},contarModulosPerfil(o){const e=this.perfiles[o];return e?(e.modulos_requeridos||[]).length+(e.modulos_opcionales||[]).length:0},contarActivosEnCategoria(o){return(this.categorias[o]?.modulos||[]).filter(o=>this.esModuloActivo(o)).length}}))});